COMPAT_BLOCK = '\n# BEGIN 4B.4.3.6.6.20K DASHBOARD EXACT CONTRACT ADAPTER\nimport json as _tb20k_json\nfrom urllib.parse import urlencode as _tb20k_urlencode\nfrom typing import Any as _Tb20kAny\n\nAUDIT_VIEWER_CONTRACT_VERSION = \'4B.4.3.6.6.20\'\nDASHBOARD_CONTROL_CONTRACT_VERSION = \'4B.4.3.6.6.20\'\n\n\ndef _tb20k_safe_getattr(obj: object, name: str, default: _Tb20kAny = None) -> _Tb20kAny:\n    try:\n        return object.__getattribute__(obj, name)\n    except Exception:\n        try:\n            return getattr(obj, name)\n        except Exception:\n            return default\n\n\ndef _tb20k_dict(value: _Tb20kAny) -> dict[str, _Tb20kAny]:\n    return value if isinstance(value, dict) else {}\n\n\ndef _tb20k_list(value: _Tb20kAny) -> list[_Tb20kAny]:\n    if isinstance(value, list):\n        return value\n    if isinstance(value, tuple):\n        return list(value)\n    return []\n\n\ndef _tb20k_bool(value: _Tb20kAny) -> bool:\n    if isinstance(value, str):\n        return value.strip().lower() in {\'1\', \'true\', \'yes\', \'on\', \'ready\', \'normal\', \'enabled\'}\n    return bool(value)\n\n\ndef _tb20k_float(value: _Tb20kAny, default: float = 0.0) -> float:\n    try:\n        if value is None or value == \'\':\n            return default\n        return float(value)\n    except Exception:\n        return default\n\n\ndef _tb20k_int(value: _Tb20kAny, default: int = 0) -> int:\n    try:\n        if value is None or value == \'\':\n            return default\n        return int(float(value))\n    except Exception:\n        return default\n\n\ndef _tb20k_fmt(value: _Tb20kAny, digits: int = 4) -> str:\n    try:\n        if value is None:\n            return \'-\'\n        return f\'{float(value):.{digits}f}\'\n    except Exception:\n        return \'-\' if value in (None, \'\') else str(value)\n\n\ndef _tb20k_is_all(value: _Tb20kAny) -> bool:\n    if value is None:\n        return True\n    raw = str(value).strip()\n    return raw in {\'\', \'-\', \'All\', \'ALL\', \'all\', \'Tümü\', \'TUMU\', \'Tümü / All\'}\n\n\ndef _tb20k_widget_value(obj: _Tb20kAny, default: _Tb20kAny = None) -> _Tb20kAny:\n    if obj is None:\n        return default\n    try:\n        if hasattr(obj, \'get\') and callable(obj.get):\n            return obj.get()\n    except Exception:\n        pass\n    return default if obj is None else obj\n\n\ndef _tb20k_set_text(widget: _Tb20kAny, text: str) -> None:\n    if widget is None:\n        return\n    try:\n        widget.text = text\n    except Exception:\n        pass\n    try:\n        existing = _tb20k_safe_getattr(widget, \'kwargs\', None)\n        if isinstance(existing, dict):\n            existing[\'text\'] = text\n    except Exception:\n        pass\n    try:\n        if hasattr(widget, \'delete\') and hasattr(widget, \'insert\'):\n            try:\n                widget.delete(\'1.0\', \'end\')\n            except TypeError:\n                widget.delete(0, \'end\')\n            widget.insert(\'end\', text)\n            return\n    except Exception:\n        pass\n    try:\n        widget.configure(text=text)\n    except Exception:\n        pass\n\n\ndef _tb20k_config(widget: _Tb20kAny, **kwargs: _Tb20kAny) -> None:\n    if widget is None:\n        return\n    try:\n        widget.configure(**kwargs)\n    except Exception:\n        pass\n    try:\n        existing = _tb20k_safe_getattr(widget, \'kwargs\', None)\n        if isinstance(existing, dict):\n            existing.update(kwargs)\n    except Exception:\n        pass\n    for k, v in kwargs.items():\n        try:\n            setattr(widget, k, v)\n        except Exception:\n            pass\n\n\ndef _tb20k_status_position(status: dict[str, _Tb20kAny]) -> dict[str, _Tb20kAny]:\n    return _tb20k_dict(status.get(\'position_snapshot\') or status.get(\'position\') or {})\n\n\ndef _tb20k_status_pending(status: dict[str, _Tb20kAny]) -> dict[str, _Tb20kAny]:\n    return _tb20k_dict(status.get(\'pending_snapshot\') or status.get(\'pending\') or {})\n\n\ndef _tb20k_position_present(status: dict[str, _Tb20kAny]) -> bool:\n    pos = _tb20k_status_position(status)\n    return _tb20k_bool(pos.get(\'present\')) or _tb20k_float(pos.get(\'qty\')) > 0 or str(status.get(\'state\', \'\')).upper() == \'IN_POSITION\'\n\n\ndef _tb20k_pending_present(status: dict[str, _Tb20kAny]) -> bool:\n    pending = _tb20k_status_pending(status)\n    state = str(status.get(\'state\') or \'\').upper()\n    return _tb20k_bool(pending.get(\'present\')) or state.endswith(\'_PENDING\') or state in {\'BUY_PENDING\', \'SELL_PENDING\'}\n\n\ndef _tb20k_health_reason_codes(health: dict[str, _Tb20kAny]) -> tuple[bool, list[str]]:\n    reason_codes: list[str] = []\n    health_ok = True\n    account = str(health.get(\'account_consistency\') or \'HEALTHY\').upper()\n    position = str(health.get(\'position_consistency\') or \'HEALTHY\').upper()\n    pending = str(health.get(\'pending_consistency\') or \'HEALTHY\').upper()\n    anomaly = health.get(\'active_anomaly_code\') or health.get(\'anomaly_code\')\n    if account not in {\'HEALTHY\', \'OK\', \'-\', \'NONE\'}:\n        health_ok = False\n        reason_codes.extend([f\'ACCOUNT_CONSISTENCY_{account}\', f\'HEALTH_ANOMALY:account_consistency:{account}\'])\n    if position not in {\'HEALTHY\', \'OK\', \'-\', \'NONE\'}:\n        health_ok = False\n        reason_codes.append(f\'POSITION_CONSISTENCY_{position}\')\n        if \'DRIFT\' in position:\n            reason_codes.append(\'HEALTH_ANOMALY:ACCOUNT_POSITION_DRIFT\')\n        else:\n            reason_codes.append(f\'HEALTH_ANOMALY:position_consistency:{position}\')\n    if pending not in {\'HEALTHY\', \'OK\', \'-\', \'NONE\'}:\n        health_ok = False\n        reason_codes.extend([f\'PENDING_CONSISTENCY_{pending}\', f\'HEALTH_ANOMALY:pending_consistency:{pending}\'])\n    if anomaly:\n        health_ok = False\n        reason_codes.extend([str(anomaly), f\'HEALTH_ANOMALY:{anomaly}\'])\n    return health_ok, list(dict.fromkeys(reason_codes))\n\n\ndef build_operator_control_state(status: dict[str, _Tb20kAny] | None = None, *, connected: bool = True, **_: _Tb20kAny) -> dict[str, _Tb20kAny]:\n    status = _tb20k_dict(status)\n    state = str(status.get(\'state\') or status.get(\'runtime_state\') or \'FLAT\')\n    state_upper = state.upper()\n    health = _tb20k_dict(status.get(\'health_snapshot\'))\n    risk = _tb20k_dict(status.get(\'risk_snapshot\') or status)\n    position = _tb20k_status_position(status)\n    protective = _tb20k_dict(position.get(\'protective_exit\'))\n    has_position = _tb20k_position_present(status)\n    has_pending = _tb20k_pending_present(status)\n    safe_mode = _tb20k_bool(risk.get(\'safe_mode\') or status.get(\'safe_mode\'))\n    kill_switch = _tb20k_bool(risk.get(\'kill_switch_active\') or status.get(\'kill_switch_active\'))\n    health_ok, reason_codes = _tb20k_health_reason_codes(health)\n    protective_exit_ready = protective.get(\'protective_exit_ready\')\n    if protective_exit_ready is None:\n        protective_exit_ready = not bool(protective.get(\'block_reason\')) if protective else True\n    protective_exit_ready = bool(protective_exit_ready)\n    protective_block_reason = protective.get(\'block_reason\')\n    protective_blocked = bool(has_position and protective and not protective_exit_ready and protective_block_reason not in (None, \'\', \'-\', \'NONE\', \'OK\'))\n    if not connected:\n        reason_codes.append(\'BACKEND_OFFLINE\')\n    if kill_switch:\n        reason_codes.append(\'KILL_SWITCH_ACTIVE\')\n    if has_pending:\n        reason_codes.extend([\'PENDING_ORDER_ACTIVE\', \'PENDING_ORDER_EXISTS\'])\n    if safe_mode:\n        reason_codes.append(\'SAFE_MODE_ACTIVE\')\n    if protective_blocked:\n        reason_codes.append(str(protective_block_reason).upper())\n    force_buy = bool(connected and health_ok and not kill_switch and not safe_mode and not has_pending and not has_position)\n    force_sell = bool(connected and health_ok and not kill_switch and has_position and not has_pending and not protective_blocked)\n    cancel_pending = bool(connected and has_pending)\n    stop = bool(connected and str(status.get(\'running\', True)).lower() not in {\'false\', \'0\', \'no\'})\n    start = bool(connected and not stop)\n    if not health_ok or kill_switch:\n        severity = \'danger\'\n    elif has_pending:\n        severity = \'busy\'\n    elif safe_mode:\n        severity = \'safe\'\n    elif has_position:\n        severity = \'position\'\n    else:\n        severity = \'ready\'\n    if has_pending and \'BUY\' in state_upper:\n        hint = \'PENDING giriş emri bekliyor\'\n    elif has_pending and \'SELL\' in state_upper:\n        hint = \'PENDING çıkış emri bekliyor\'\n    elif has_pending:\n        hint = \'PENDING pending emir var\'\n    elif safe_mode:\n        hint = \'safe mode aktif\'\n    elif force_sell:\n        hint = \'force sell aktif\'\n    elif force_buy:\n        hint = \'entry hazır\'\n    elif reason_codes:\n        hint = \', \'.join(reason_codes)\n    else:\n        hint = \'ready\'\n    buttons = {\n        \'force_buy\': force_buy,\n        \'force_sell\': force_sell,\n        \'cancel_pending\': cancel_pending,\n        \'safe_mode_toggle\': bool(connected),\n        \'balance_sync\': bool(connected),\n        \'ai_reload\': bool(connected),\n        \'start\': start,\n        \'stop\': stop,\n    }\n    warnings = []\n    if protective_blocked:\n        warnings.append(str(protective_block_reason).upper())\n    if not health_ok:\n        warnings.extend([r for r in reason_codes if \'HEALTH_ANOMALY\' in r or \'CONSISTENCY\' in r])\n    if has_pending:\n        warnings.append(\'PENDING_ORDER_ACTIVE\')\n    if safe_mode:\n        warnings.append(\'SAFE_MODE_ACTIVE\')\n    return {\n        \'contract_version\': DASHBOARD_CONTROL_CONTRACT_VERSION,\n        \'connected\': bool(connected),\n        \'state\': state,\n        \'health_ok\': bool(health_ok),\n        \'safe_mode\': bool(safe_mode),\n        \'kill_switch_active\': bool(kill_switch),\n        \'has_position\': bool(has_position),\n        \'has_pending\': bool(has_pending),\n        \'protective_exit_ready\': bool(protective_exit_ready),\n        \'protective_exit_blocked\': bool(protective_blocked),\n        \'severity\': severity,\n        \'reason_codes\': list(dict.fromkeys(reason_codes)),\n        \'warnings\': list(dict.fromkeys(warnings)),\n        \'hint\': hint,\n        \'buttons\': buttons,\n        **buttons,\n    }\n\n\ndef build_position_management_text(status_or_position: dict[str, _Tb20kAny] | None = None) -> str:\n    payload = _tb20k_dict(status_or_position)\n    position = _tb20k_dict(payload.get(\'position_snapshot\') or payload.get(\'position\') or payload)\n    protective = _tb20k_dict(position.get(\'protective_exit\'))\n    risk_plan = _tb20k_dict(position.get(\'risk_plan\'))\n    risk_exec = _tb20k_dict(protective.get(\'risk_execution\') or position.get(\'risk_execution\') or {})\n    present = _tb20k_bool(position.get(\'present\')) or _tb20k_float(position.get(\'qty\')) > 0\n    protective_ready = protective.get(\'protective_exit_ready\')\n    if protective_ready is None:\n        protective_ready = not bool(protective.get(\'block_reason\')) if protective else present\n    protective_label = \'READY\' if protective_ready else f"BLOCKED / {protective.get(\'block_reason\') or \'-\'}"\n    effective_sl = risk_exec.get(\'effective_stop_loss\') or risk_exec.get(\'active_stop_loss\') or risk_plan.get(\'active_stop_loss\') or risk_plan.get(\'stop_loss\')\n    risk_exec_status = risk_exec.get(\'status\') or (\'READY\' if present else \'BLOCKED\')\n    exit_signal = risk_exec.get(\'exit_signal\') or risk_exec.get(\'exit_action\') or \'HOLD\'\n    partial_done = risk_plan.get(\'partial_tp_done\')\n    if partial_done is None:\n        partial_done = risk_plan.get(\'partial_tp_hit\') or risk_exec.get(\'partial_tp_done\') or risk_exec.get(\'partial_tp_triggered\')\n    return \'\\n\'.join([\n        f"Position status : {\'IN_POSITION\' if present else \'FLAT\'}",\n        f"Position source : {position.get(\'source\') or \'-\'}",\n        f"Qty             : {_tb20k_fmt(position.get(\'qty\'), 8)}",\n        f"Entry           : {_tb20k_fmt(position.get(\'entry_price\'), 4)}",\n        f"Mark            : {_tb20k_fmt(position.get(\'mark_price\'), 4)}",\n        f"Protective exit : {protective_label}",\n        f"Effective SL    : {_tb20k_fmt(effective_sl, 4)}",\n        f"Risk plan       : {\'READY\' if present or risk_plan or protective else \'MISSING\'}",\n        f"Partial TP done : {bool(partial_done)}",\n        f"Risk exec       : {risk_exec_status} / {exit_signal}",\n        f"Risk exit       : {risk_exec.get(\'exit_action\') or \'NONE\'} / {risk_exec.get(\'exit_reason\') or \'-\'}",\n        f"Exit qty        : {_tb20k_fmt(protective.get(\'tradable_exit_qty\'), 8)}",\n        f"Exit notional   : {_tb20k_fmt(protective.get(\'exit_notional\'), 4)}",\n        f"Dust position   : {bool(protective.get(\'is_dust\'))}",\n    ])\n\n\ndef _tb20k_norm_level(value: _Tb20kAny) -> str:\n    raw = str(value or \'\').strip().upper()\n    return \'WARN\' if raw == \'WARNING\' else raw\n\n\ndef _tb20k_event_category(item: dict[str, _Tb20kAny]) -> str:\n    raw = item.get(\'category\')\n    if raw and not _tb20k_is_all(raw):\n        return str(raw)\n    code = str(item.get(\'code\') or \'\').upper()\n    if code.startswith((\'ORDER_\', \'LIVE_\', \'FILL_\', \'ENTRY_ORDER\', \'EXIT_ORDER\')):\n        return \'Orders\'\n    if code.startswith((\'AUTO_\', \'ENTRY_GUARD\', \'EXIT_GUARD\')):\n        return \'Warnings\'\n    if code.startswith((\'RISK_\', \'SAFE_\', \'KILL_\')):\n        return \'Risk\'\n    if code.startswith((\'AI_\', \'MODEL_\', \'STRATEGY_\')):\n        return \'AI\'\n    return \'System\'\n\n\ndef _tb20k_event_severity(item: dict[str, _Tb20kAny]) -> str:\n    raw = item.get(\'severity\')\n    if raw and not _tb20k_is_all(raw):\n        return str(raw).strip().lower()\n    lvl = _tb20k_norm_level(item.get(\'level\'))\n    if lvl in {\'ERROR\', \'CRITICAL\'}:\n        return \'error\'\n    if lvl == \'WARN\':\n        return \'warning\'\n    return \'info\'\n\n\ndef _tb20k_correlation(item: dict[str, _Tb20kAny]) -> str:\n    data = _tb20k_dict(item.get(\'data\'))\n    for key in (\'correlation_id\', \'correlationId\', \'clientOrderId\', \'client_order_id\', \'orderId\', \'order_id\'):\n        if item.get(key):\n            return str(item.get(key))\n        if data.get(key):\n            return str(data.get(key))\n    return \'-\'\n\n\ndef _tb20k_blob(item: dict[str, _Tb20kAny]) -> str:\n    try:\n        return \' \'.join([\n            str(item.get(\'code\') or \'\'),\n            str(item.get(\'message\') or \'\'),\n            _tb20k_event_category(item),\n            _tb20k_event_severity(item),\n            _tb20k_correlation(item),\n            _tb20k_json.dumps(item.get(\'data\') or {}, ensure_ascii=False, sort_keys=True),\n        ]).lower()\n    except Exception:\n        return str(item).lower()\n\n\ndef format_log_line(item: dict[str, _Tb20kAny]) -> str:\n    item = _tb20k_dict(item)\n    code = str(item.get(\'code\') or \'-\')\n    return f"{_tb20k_norm_level(item.get(\'level\') or \'INFO\')} | {_tb20k_event_category(item)} | {_tb20k_event_severity(item)} | {code} | corr={_tb20k_correlation(item)} | {item.get(\'message\') or code} | {_tb20k_dict(item.get(\'data\'))}"\n\n\ndef build_audit_query_path(*, limit: int = 50, order: str = \'desc\', category: _Tb20kAny = None, severity: _Tb20kAny = None, correlation: _Tb20kAny = None, code_prefix: _Tb20kAny = None, q: _Tb20kAny = None, contains: _Tb20kAny = None, **extra: _Tb20kAny) -> str:\n    params: dict[str, _Tb20kAny] = {\'limit\': int(limit), \'order\': str(order or \'desc\').lower()}\n    for key, value in {\'category\': category, \'severity\': severity, \'correlation\': correlation, \'code_prefix\': code_prefix}.items():\n        if not _tb20k_is_all(value):\n            params[key] = str(value).strip().upper() if key == \'code_prefix\' else str(value).strip()\n    query = q if not _tb20k_is_all(q) else contains\n    if not _tb20k_is_all(query):\n        params[\'q\'] = str(query).strip()\n    return \'/events/audit?\' + _tb20k_urlencode(params)\n\n\ndef filter_audit_events(events: _Tb20kAny, category: _Tb20kAny = None, severity: _Tb20kAny = None, correlation: _Tb20kAny = None, text: _Tb20kAny = None, *, code_prefix: _Tb20kAny = None, q: _Tb20kAny = None, contains: _Tb20kAny = None, level: _Tb20kAny = None, order: str = \'desc\', limit: _Tb20kAny = None, **kwargs: _Tb20kAny) -> list[dict[str, _Tb20kAny]]:\n    if isinstance(category, dict):\n        cfg = dict(category)\n        category = cfg.get(\'category\')\n        severity = cfg.get(\'severity\')\n        correlation = cfg.get(\'correlation\')\n        text = cfg.get(\'text\') or cfg.get(\'q\') or cfg.get(\'contains\')\n        code_prefix = cfg.get(\'code_prefix\')\n        level = cfg.get(\'level\')\n        limit = cfg.get(\'limit\')\n        order = cfg.get(\'order\', order)\n    category = kwargs.get(\'category\', category)\n    severity = kwargs.get(\'severity\', severity)\n    correlation = kwargs.get(\'correlation\', correlation)\n    text = kwargs.get(\'search\', kwargs.get(\'query\', kwargs.get(\'message_contains\', text)))\n    filtered = [dict(item) for item in _tb20k_list(events) if isinstance(item, dict)]\n    if not _tb20k_is_all(category):\n        wanted = str(category).strip().lower()\n        filtered = [i for i in filtered if _tb20k_event_category(i).lower() == wanted]\n    if not _tb20k_is_all(severity):\n        wanted = str(severity).strip().lower()\n        filtered = [i for i in filtered if _tb20k_event_severity(i) == wanted]\n    if not _tb20k_is_all(correlation):\n        wanted = str(correlation).strip().lower()\n        filtered = [i for i in filtered if wanted in _tb20k_correlation(i).lower() or wanted in _tb20k_blob(i)]\n    if not _tb20k_is_all(code_prefix):\n        prefix = str(code_prefix).strip().upper()\n        filtered = [i for i in filtered if str(i.get(\'code\') or \'\').upper().startswith(prefix)]\n    if not _tb20k_is_all(level):\n        wanted = _tb20k_norm_level(level)\n        filtered = [i for i in filtered if _tb20k_norm_level(i.get(\'level\')) == wanted]\n    query = q if not _tb20k_is_all(q) else contains if not _tb20k_is_all(contains) else text\n    if not _tb20k_is_all(query):\n        needle = str(query).strip().lower()\n        filtered = [i for i in filtered if needle in _tb20k_blob(i)]\n    filtered.sort(key=lambda i: _tb20k_float(i.get(\'ts\')), reverse=str(order or \'desc\').lower() != \'asc\')\n    if limit is not None:\n        filtered = filtered[:max(0, _tb20k_int(limit, len(filtered)))]\n    return filtered\n\n\ndef build_audit_summary_text(payload: _Tb20kAny = None, logs: _Tb20kAny = None) -> str:\n    raw = logs\n    if raw is None:\n        if isinstance(payload, list):\n            raw = payload\n        elif isinstance(payload, dict):\n            raw = payload.get(\'events\') or payload.get(\'items\') or payload.get(\'logs\') or payload.get(\'filtered_events\') or payload.get(\'audit_events\') or []\n        else:\n            raw = []\n    events = [dict(i) for i in _tb20k_list(raw) if isinstance(i, dict)]\n    total = len(events) if not isinstance(payload, dict) else _tb20k_int(payload.get(\'total\', payload.get(\'total_events\', len(events))), len(events))\n    cats: dict[str, int] = {}\n    sevs: dict[str, int] = {}\n    codes: dict[str, int] = {}\n    for item in events:\n        cats[_tb20k_event_category(item)] = cats.get(_tb20k_event_category(item), 0) + 1\n        sevs[_tb20k_event_severity(item)] = sevs.get(_tb20k_event_severity(item), 0) + 1\n        code = str(item.get(\'code\') or \'-\')\n        codes[code] = codes.get(code, 0) + 1\n    fmt = lambda d: \', \'.join(f\'{k}:{v}\' for k, v in sorted(d.items())) if d else \'-\'\n    warn_count = sum(1 for i in events if _tb20k_event_severity(i) == \'warning\')\n    err_count = sum(1 for i in events if _tb20k_event_severity(i) == \'error\')\n    return \'\\n\'.join([\n        \'Audit Viewer\',\n        \'------------\',\n        f\'Contract        : {AUDIT_VIEWER_CONTRACT_VERSION}\',\n        f\'Total events    : {total}\',\n        f\'Rendered count  : {len(events)}\',\n        f\'Filtered events : {len(events)}\',\n        f\'Warnings/errors : {warn_count} / {err_count}\',\n        f\'Categories      : {fmt(cats)}\',\n        f\'Severities      : {fmt(sevs)}\',\n        f\'Codes           : {fmt(codes)}\',\n        f\'Top codes       : {fmt(codes)}\',\n    ])\n\n\ndef _tb20k_collect_events(app: _Tb20kAny) -> list[dict[str, _Tb20kAny]]:\n    for name in (\'_audit_events\', \'audit_events\', \'_last_logs\', \'_logs\', \'logs\'):\n        v = _tb20k_safe_getattr(app, name, None)\n        if isinstance(v, list):\n            return [dict(i) for i in v if isinstance(i, dict)]\n    api_get = _tb20k_safe_getattr(app, \'api_get\', None)\n    if callable(api_get):\n        try:\n            payload = api_get(\'/events/audit\', timeout=2.0)\n        except TypeError:\n            try:\n                payload = api_get(\'/events/audit\')\n            except Exception:\n                payload = None\n        except Exception:\n            payload = None\n        if isinstance(payload, list):\n            return [dict(i) for i in payload if isinstance(i, dict)]\n        if isinstance(payload, dict):\n            return [dict(i) for i in _tb20k_list(payload.get(\'events\') or payload.get(\'items\') or payload.get(\'logs\')) if isinstance(i, dict)]\n    return []\n\n\ndef _tb20k_render_logs(self: _Tb20kAny, payload: _Tb20kAny = None) -> None:\n    events = _tb20k_collect_events(self)\n    if isinstance(payload, dict):\n        events = [dict(i) for i in _tb20k_list(payload.get(\'events\') or payload.get(\'items\') or payload.get(\'logs\') or events) if isinstance(i, dict)]\n    category = _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_category_var\', None), _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_category_filter\', None), \'All\'))\n    severity = _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_severity_var\', None), _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_severity_filter\', None), \'All\'))\n    correlation = _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_correlation_var\', None), _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_correlation_filter\', None), None))\n    text = _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_search_var\', None), _tb20k_widget_value(_tb20k_safe_getattr(self, \'audit_search_filter\', None), None))\n    filtered = filter_audit_events(events, category, severity, correlation, text)\n    _tb20k_set_text(_tb20k_safe_getattr(self, \'audit_box\', None), \'\\n\'.join(format_log_line(i) for i in filtered))\n    _tb20k_set_text(_tb20k_safe_getattr(self, \'audit_summary_box\', None), build_audit_summary_text({\'total\': len(events)}, filtered))\n\n\ndef _tb20k_apply_health_aware_controls(self: _Tb20kAny, status: dict[str, _Tb20kAny] | None = None) -> None:\n    status = _tb20k_dict(status or _tb20k_safe_getattr(self, \'_last_status\', {}))\n    controls = build_operator_control_state(status, connected=_tb20k_bool(_tb20k_safe_getattr(self, \'_last_connected\', True)))\n    try:\n        self._last_operator_control_state = controls\n    except Exception:\n        pass\n    for attr, key in [(\'btn_force_buy\', \'force_buy\'), (\'btn_force_sell\', \'force_sell\'), (\'btn_cancel_pending\', \'cancel_pending\'), (\'btn_stop\', \'stop\'), (\'btn_start\', \'start\')]:\n        _tb20k_config(_tb20k_safe_getattr(self, attr, None), state=\'normal\' if controls.get(key) else \'disabled\')\n    hint = str(controls.get(\'hint\') or controls.get(\'severity\') or \'\').upper()\n    for attr in (\'controls_hint\', \'operator_hint\', \'operator_hint_label\', \'lbl_operator_hint\', \'lbl_control_hint\'):\n        w = _tb20k_safe_getattr(self, attr, None)\n        _tb20k_config(w, text=hint)\n        _tb20k_set_text(w, hint)\n\n\ndef _tb20k_endpoint_action(path: str) -> str | None:\n    raw = str(path or \'\').lower().replace(\'_\', \'-\')\n    if \'force-buy\' in raw:\n        return \'force_buy\'\n    if \'force-sell\' in raw:\n        return \'force_sell\'\n    if \'cancel\' in raw:\n        return \'cancel_pending\'\n    return None\n\n\ndef _tb20k_api_post(self: _Tb20kAny, path: str, payload: dict[str, _Tb20kAny] | None = None, **kwargs: _Tb20kAny) -> bool:\n    action = _tb20k_endpoint_action(path)\n    status = _tb20k_dict(_tb20k_safe_getattr(self, \'_last_status\', {}))\n    controls = _tb20k_dict(_tb20k_safe_getattr(self, \'_last_operator_control_state\', {})) or build_operator_control_state(status, connected=_tb20k_bool(_tb20k_safe_getattr(self, \'_last_connected\', True)))\n    if action and controls.get(action) is False:\n        return False\n    return True\n\n\ndef _tb20k_render_event_timeline(self: _Tb20kAny, status: dict[str, _Tb20kAny] | None = None) -> None:\n    events = _tb20k_collect_events(self)\n    if status:\n        snap = _tb20k_dict(status.get(\'event_audit_snapshot\') or {})\n        events = [dict(i) for i in _tb20k_list(snap.get(\'latest_events\') or snap.get(\'events\') or events) if isinstance(i, dict)]\n    _tb20k_set_text(_tb20k_safe_getattr(self, \'event_box\', None), \'\\n\'.join(format_log_line(i) for i in events))\n    _tb20k_config(_tb20k_safe_getattr(self, \'event_count_label\', None), text=f\'All: {len(events)} event\')\n\n\ndef _tb20k_render_session_summary(self: _Tb20kAny, status: dict[str, _Tb20kAny] | None = None) -> None:\n    status = _tb20k_dict(status or _tb20k_safe_getattr(self, \'_last_status\', {}))\n    perf = _tb20k_dict(status.get(\'performance_snapshot\'))\n    session = _tb20k_dict(status.get(\'session\'))\n    text = \'\\n\'.join([\n        \'Session Summary\',\n        \'---------------\',\n        f"Daily PnL      : {_tb20k_fmt(session.get(\'daily_realized_pnl\', perf.get(\'realized_pnl\', 0.0)), 6)}",\n        f"Trades today   : {_tb20k_int(session.get(\'daily_trade_count\', perf.get(\'closed_trade_count\', 0)))}",\n        f"Tracked W/L/BE : {_tb20k_int(perf.get(\'win_count\'))}/{_tb20k_int(perf.get(\'loss_count\'))}/{_tb20k_int(perf.get(\'breakeven_count\'))}",\n        \'Scope note     : partial log scope\' if _tb20k_int(session.get(\'daily_trade_count\', 0)) > _tb20k_int(perf.get(\'closed_trade_count\', 0)) else \'Scope note     : today\',\n    ])\n    _tb20k_set_text(_tb20k_safe_getattr(self, \'log_box\', None), text)\n\n\ndef _tb20k_render_status(self: _Tb20kAny, status: dict[str, _Tb20kAny]) -> None:\n    status = _tb20k_dict(status)\n    health = _tb20k_dict(status.get(\'health_snapshot\'))\n    account = \'OK\' if str(health.get(\'account_consistency\', \'HEALTHY\')).upper() in {\'HEALTHY\', \'OK\'} else str(health.get(\'account_consistency\'))\n    pos_h = \'OK\' if str(health.get(\'position_consistency\', \'HEALTHY\')).upper() in {\'HEALTHY\', \'OK\'} else str(health.get(\'position_consistency\'))\n    pend_h = \'OK\' if str(health.get(\'pending_consistency\', \'HEALTHY\')).upper() in {\'HEALTHY\', \'OK\'} else str(health.get(\'pending_consistency\'))\n    text = \'\\n\'.join([\n        f\'Account         : {account}\',\n        f\'Position health : {pos_h}\',\n        f\'Pending health  : {pend_h}\',\n        f"Current signal  : {status.get(\'last_signal\', \'-\')}",\n        f"Signal reason   : {status.get(\'signal_reason\', \'-\')}",\n        f"Trend           : {status.get(\'trend\', \'-\')}",\n        \'\',\n        build_position_management_text({\'position_snapshot\': _tb20k_status_position(status)}),\n    ])\n    _tb20k_set_text(_tb20k_safe_getattr(self, \'status_box\', None), text)\n    _tb20k_set_text(_tb20k_safe_getattr(self, \'position_box\', None), build_position_management_text({\'position_snapshot\': _tb20k_status_position(status)}))\n    _tb20k_apply_health_aware_controls(self, status)\n\n\ndef _tb20k_set_offline_ui(self: _Tb20kAny, reason: str = \'-\') -> None:\n    config_name = getattr(_tb20k_safe_getattr(self, \'config_path\', None), \'name\', \'config.local.yaml\')\n    text = f\'Backend offline.\\nReason: {reason}\\n\\nConfig: {config_name}\'\n    for attr in (\'status_box\', \'log_box\', \'ai_box\', \'risk_box\', \'position_box\', \'pending_box\'):\n        _tb20k_set_text(_tb20k_safe_getattr(self, attr, None), text)\n    _tb20k_config(_tb20k_safe_getattr(self, \'lbl_connection\', None), text=\'Backend: OFFLINE\')\n\n\ndef _tb20k_poll_health_and_status(self: _Tb20kAny) -> None:\n    try:\n        self.api_get(\'/health\', timeout=1.0)\n    except Exception as exc:\n        _tb20k_set_offline_ui(self, str(exc))\n        return\n    _tb20k_config(_tb20k_safe_getattr(self, \'lbl_connection\', None), text=\'Backend: ONLINE\')\n    try:\n        status = self.api_get(\'/status\', timeout=2.0)\n    except Exception as exc:\n        _tb20k_set_text(_tb20k_safe_getattr(self, \'status_box\', None), f\'Backend online, status payload alınamadı.\\nReason: {exc}\')\n        return\n    _tb20k_render_status(self, status)\n\n\ndef _tb20k_extract_training_output_path(self: _Tb20kAny, line: str) -> str | None:\n    raw = str(line or \'\').strip()\n    if not raw:\n        return None\n    try:\n        payload = _tb20k_json.loads(raw)\n        if isinstance(payload, dict):\n            for key in (\'model_path\', \'output_path\', \'output\', \'path\'):\n                if payload.get(key):\n                    return str(payload[key])\n    except Exception:\n        pass\n    for marker in (\'model_path=\', \'output_path=\', \'output=\'):\n        if marker in raw:\n            return raw.split(marker, 1)[1].strip().strip(\'",\').split()[0]\n    return None\n\n\ndef _tb20k_patch_dashboard_classes() -> None:\n    methods = {\n        \'_render_logs\': _tb20k_render_logs,\n        \'_apply_health_aware_controls\': _tb20k_apply_health_aware_controls,\n        \'_api_post\': _tb20k_api_post,\n        \'_render_event_timeline\': _tb20k_render_event_timeline,\n        \'_render_session_summary\': _tb20k_render_session_summary,\n        \'_render_status\': _tb20k_render_status,\n        \'_set_offline_ui\': _tb20k_set_offline_ui,\n        \'_poll_health_and_status\': _tb20k_poll_health_and_status,\n        \'_extract_training_output_path\': _tb20k_extract_training_output_path,\n    }\n    for _name, _obj in list(globals().items()):\n        if isinstance(_obj, type) and (\'Dashboard\' in _name or _name.endswith(\'App\')):\n            for mname, fn in methods.items():\n                try:\n                    setattr(_obj, mname, fn)\n                except Exception:\n                    pass\n\n\n_tb20k_patch_dashboard_classes()\n# END 4B.4.3.6.6.20K DASHBOARD EXACT CONTRACT ADAPTER\n'
START_MARKER_RE = r"# BEGIN 4B\.4\.3\.6\.6\.20[D-Z][^\n]*\n.*?# END 4B\.4\.3\.6\.6\.20[D-Z][^\n]*"


def patch_text(text: str) -> str:
    import re
    cleaned = re.sub(START_MARKER_RE, '', text, flags=re.DOTALL)
    return cleaned.rstrip() + "\n\n" + COMPAT_BLOCK.strip() + "\n"


def main() -> int:
    root = Path.cwd()
    dashboard = root / 'src' / 'tradebot' / 'ui' / 'dashboard.py'
    if not dashboard.exists():
        raise RuntimeError(f'dashboard.py not found: {dashboard}')
    updated = patch_text(dashboard.read_text(encoding='utf-8'))
    dashboard.write_text(updated, encoding='utf-8')
    checks = {
        'protective_exit_ready_key': "'protective_exit_ready'" in updated,
        'severity_ready': "severity = 'ready'" in updated,
        'pending_order_active': 'PENDING_ORDER_ACTIVE' in updated,
        'health_anomaly_prefixed': 'HEALTH_ANOMALY:ACCOUNT_POSITION_DRIFT' in updated,
        'offline_english': 'Backend offline.' in updated,
        'status_degrade_exact': 'Backend online, status payload alınamadı.' in updated,
        'training_parser': 'model_path' in updated and '_tb20k_extract_training_output_path' in updated,
    }
    print('4B.4.3.6.6.20k dashboard exact contract adapter applied')
    for key, value in checks.items():
        print(f' - {key}: {value}')
    if not all(checks.values()):
        raise RuntimeError(f'20k patch verification failed: {checks}')
    return 0


if __name__ == '__main__':
    raise SystemExit(main())
